mapper.select:
SELECT group_id, group_name, book_title, headcount_min, headcount_max, content, style, status, end_date, created_at, updated_at, user_id, code_id FROM `groups`
AND style = #{style}
AND status = #{status}
AND code_id = #{location}
AND group_id IN (SELECT group_id FROM group_scraps WHERE user_id = #{userId})
AND group_id NOT IN (SELECT group_id FROM group_scraps WHERE user_id = #{userId})
ORDER BY created_at DESC

mapper.update:
UPDATE `groups`
group_name = #{groupName}, book_title = #{bookTitle}, headcount_min = #{headcountMin}, headcount_max = #{headcountMax}, content = #{content}, style = #{style}, status = #{status}, end_date = #{endDate},
WHERE group_id = #{groupId}
